import { formatTrademarkSymbols } from "@/lib/textFormatting";
import { useState, useEffect, useRef, useCallback, useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Navigation, Maximize, Minimize, MapPin, Star, MoreHorizontal, Filter, ChevronUp, ChevronDown, Landmark, UtensilsCrossed } from "lucide-react";
import { getTypeDisplayLabel } from "@/hooks/useRestaurants";
import { useMichelinMarkers, useMichelinList } from "@/hooks/useLandmarks";
import { useTranslation } from "react-i18next";
import { calculateDistance, getUserLocation } from "@/lib/geolocation";
import RestaurantMap from "@/components/RestaurantMap";
import { useToast } from "@/hooks/use-toast";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useAutoTranslateNames } from "@/hooks/useAutoTranslateNames";
import mapboxgl from "mapbox-gl";
import { supabase } from "@/integrations/supabase/client";
import logoIcon from "@/assets/xiaoxiong-logo-clean.png";
import LocationPermissionDialog from "@/components/LocationPermissionDialog";

const MapRestaurantTags = ({ restaurant, language }: { 
  restaurant: any; 
  language: string;
}) => {
  const [visibleCount, setVisibleCount] = useState(999);
  const containerRef = useRef<HTMLDivElement>(null);
  
  const allTags = restaurant.type.slice(0, 3).map((type: string, idx: number) => ({ 
    key: `type-${idx}`, 
    label: getTypeDisplayLabel(type, language), 
    variant: "secondary" as const,
    color: undefined 
  }));
  
  useEffect(() => {
    const checkOverflow = () => {
      if (!containerRef.current) return;
      
      const container = containerRef.current;
      const badges = Array.from(container.querySelectorAll('.tag-badge')) as HTMLElement[];
      
      if (badges.length === 0) {
        setTimeout(checkOverflow, 50);
        return;
      }
      
      const firstBadgeTop = badges[0]?.offsetTop;
      let lastVisibleIndex = badges.length;
      
      for (let i = 0; i < badges.length; i++) {
        if (badges[i].offsetTop > firstBadgeTop) {
          lastVisibleIndex = i;
          break;
        }
      }
      
      if (lastVisibleIndex < badges.length) {
        lastVisibleIndex = Math.max(1, lastVisibleIndex - 1);
      }
      
      setVisibleCount(lastVisibleIndex);
    };
    
    setVisibleCount(999);
    const timer = setTimeout(checkOverflow, 100);
    
    window.addEventListener('resize', checkOverflow);
    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', checkOverflow);
    };
  }, [allTags.length, restaurant.id]);
  
  const visibleTags = allTags.slice(0, visibleCount);
  const hasMore = allTags.length > visibleCount;
  
  return (
    <div className="flex items-center gap-2">
      <div ref={containerRef} className="flex gap-1.5 flex-wrap flex-1">
        {visibleTags.map((tag) => (
          <Badge 
            key={tag.key} 
            variant={tag.variant}
            className="text-xs font-medium whitespace-nowrap tag-badge"
            style={tag.color ? { backgroundColor: tag.color, color: 'white' } : undefined}
          >
            {tag.label}
          </Badge>
        ))}
      </div>
      {hasMore && (
        <Popover>
          <PopoverTrigger asChild>
            <Button variant="ghost" size="sm" className="h-6 px-2 text-muted-foreground hover:text-foreground flex-shrink-0">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-80">
            <div className="flex flex-wrap gap-2">
              {allTags.map((tag) => (
                <Badge 
                  key={tag.key} 
                  variant={tag.variant}
                  className="text-xs font-medium"
                  style={tag.color ? { backgroundColor: tag.color, color: 'white' } : undefined}
                >
                  {tag.label}
                </Badge>
              ))}
            </div>
          </PopoverContent>
        </Popover>
      )}
    </div>
  );
};

const HomeMapSection = () => {
  const navigate = useNavigate();
  const { t, i18n } = useTranslation();
  const { toast } = useToast();
  const { localizeRestaurant, getLocalizedField, getNameWithOriginal } = useLocalizedContent();
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCountry, setSelectedCountry] = useState<string | null>(null);
  const [radiusFilter, setRadiusFilter] = useState<number | null>(null);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const mapRef = useRef<mapboxgl.Map | null>(null);
  const savedMapState = useRef<{ center: [number, number]; zoom: number } | null>(null);
  const restaurantRefs = useRef<{ [key: string]: HTMLDivElement | null }>({});
  const [selectedRestaurantId, setSelectedRestaurantId] = useState<string | null>(null);
  const [selectedMarkerItem, setSelectedMarkerItem] = useState<any>(null);
  const [showFilters, setShowFilters] = useState(false);
  const [showLocationDialog, setShowLocationDialog] = useState(false);
  const [isMapCollapsed, setIsMapCollapsed] = useState(false);
  const [isMobileListExpanded, setIsMobileListExpanded] = useState(false);
  const [countryName, setCountryName] = useState<string | null>(null);
  const [countryBbox, setCountryBbox] = useState<[number, number, number, number] | null>(null);

  const MOBILE_DEFAULT_VISIBLE = 4;

  // Auto-detect location silently if permission was previously granted
  useEffect(() => {
    if (navigator.permissions) {
      navigator.permissions.query({ name: 'geolocation' }).then((result) => {
        if (result.state === 'granted') {
          navigator.geolocation.getCurrentPosition(
            (position) => {
              setUserLocation({
                lat: position.coords.latitude,
                lng: position.coords.longitude,
              });
            },
            () => {}, // silently fail
            { enableHighAccuracy: false, timeout: 5000, maximumAge: 300000 }
          );
        }
      }).catch(() => {}); // permissions API not supported, skip
    }
  }, []);

  // Reverse geocode to get country name when location is available
  useEffect(() => {
    if (!userLocation) return;
    const MAPBOX_TOKEN = import.meta.env.VITE_MAPBOX_TOKEN;
    if (!MAPBOX_TOKEN) return;
    fetch(`https://api.mapbox.com/geocoding/v5/mapbox.places/${userLocation.lng},${userLocation.lat}.json?types=country&access_token=${MAPBOX_TOKEN}&language=${i18n.language}`)
      .then(res => res.json())
      .then(data => {
        if (data.features?.[0]?.text) {
          setCountryName(data.features[0].text);
        }
        // Use mainland-only bbox for countries with distant islands
        const countryCode = data.features?.[0]?.properties?.short_code;
        if (countryCode === 'pt') {
          // Mainland Portugal only, excluding Azores & Madeira
          setCountryBbox([-9.5, 36.9, -6.2, 42.2]);
        } else if (data.features?.[0]?.bbox) {
          setCountryBbox(data.features[0].bbox as [number, number, number, number]);
        }
      })
      .catch(() => {});
  }, [userLocation, i18n.language]);

  const { data: markerData, isLoading } = useMichelinMarkers(searchQuery);
  const {
    data: listPages,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
  } = useMichelinList(searchQuery, userLocation, radiusFilter, selectedCountry);

  const SUPPORTED_COUNTRIES = [
    { db: "Portugal", flag: "🇵🇹" }, { db: "Spain", flag: "🇪🇸" },
    { db: "France", flag: "🇫🇷" }, { db: "Germany", flag: "🇩🇪" },
    { db: "Italy", flag: "🇮🇹" }, { db: "UK", flag: "🇬🇧" },
    { db: "Japan", flag: "🇯🇵" }, { db: "Korea", flag: "🇰🇷" },
    { db: "China", flag: "🇨🇳" }, { db: "USA", flag: "🇺🇸" },
    { db: "Saudi Arabia", flag: "🇸🇦" }, { db: "Mexico", flag: "🇲🇽" },
    { db: "Vietnam", flag: "🇻🇳" }, { db: "Singapore", flag: "🇸🇬" },
    { db: "Hungary", flag: "🇭🇺" },
  ];

  const COUNTRY_I18N_MAP: Record<string, string> = {
    "Portugal": "Portugal", "Spain": "Spain", "France": "France",
    "Germany": "Germany", "Italy": "Italy", "UK": "United Kingdom",
    "Japan": "Japan", "Korea": "South Korea", "China": "China",
    "USA": "United States", "Saudi Arabia": "Saudi Arabia",
    "Mexico": "Mexico", "Vietnam": "Vietnam", "Singapore": "Singapore",
    "Hungary": "Hungary",
  };

  const COUNTRY_BBOX: Record<string, [number, number, number, number]> = {
    "Portugal": [-9.5, 36.9, -6.2, 42.2],
    "Spain": [-9.3, 36.0, 3.3, 43.8],
    "France": [-5.1, 42.3, 8.2, 51.1],
    "Germany": [5.9, 47.3, 15.0, 55.1],
    "Italy": [6.6, 36.6, 18.5, 47.1],
    "UK": [-8.2, 49.9, 1.8, 60.9],
    "Japan": [129.5, 31.0, 145.8, 45.5],
    "Korea": [126.0, 34.0, 130.0, 38.6],
    "China": [73.5, 18.2, 134.8, 53.6],
    "USA": [-125.0, 24.5, -66.9, 49.4],
    "Saudi Arabia": [34.5, 16.4, 55.7, 32.2],
    "Mexico": [-118.4, 14.5, -86.7, 32.7],
    "Vietnam": [102.1, 8.4, 109.5, 23.4],
    "Singapore": [103.6, 1.2, 104.0, 1.5],
    "Hungary": [16.1, 45.7, 22.9, 48.6],
  };

  const handleRequestLocation = () => {
    setShowLocationDialog(true);
  };

  const requestLocation = async () => {
    setShowLocationDialog(false);
    try {
      const position = await getUserLocation();
      setUserLocation({
        lat: position.coords.latitude,
        lng: position.coords.longitude,
      });
      toast({
        title: t("restaurants.locationEnabled"),
        description: t("restaurants.sortByDistance"),
      });
    } catch (error: any) {
      console.error("Location error:", error);
    }
  };

  const handleRadiusChange = (radius: number | null) => {
    setRadiusFilter(radius);
    if (radius && !userLocation) {
      handleRequestLocation();
    }
  };

  // ── Map markers: ultra-lightweight, with distance + filtering ──
  const mapMarkers = useMemo(() => {
    if (!markerData) return [];
    let markers = markerData.map(m => {
      if (userLocation) {
        const distance = calculateDistance(userLocation.lat, userLocation.lng, m.lat, m.lng);
        return { ...m, distance };
      }
      return { ...m, distance: undefined as number | undefined };
    });

    if (selectedCountry) {
      markers = markers.filter(m => (m as any).country === selectedCountry);
    }

    if (radiusFilter && userLocation) {
      markers = markers
        .filter(m => m.distance !== undefined && m.distance <= radiusFilter)
        .sort((a, b) => (a.distance || 0) - (b.distance || 0));
    } else if (userLocation) {
      markers.sort((a, b) => (a.distance || 0) - (b.distance || 0));
    }

    return markers;
  }, [markerData, userLocation, radiusFilter, selectedCountry]);

  // ── Sidebar list: paginated, loaded on-demand ──
  const listItems = useMemo(() => {
    if (!listPages) return [];
    const all = listPages.pages.flatMap(p => p.items);
    const items = all.map(restaurant => {
      const localized = localizeRestaurant(restaurant);
      if (userLocation) {
        const distance = calculateDistance(userLocation.lat, userLocation.lng, restaurant.lat, restaurant.lng);
        return { ...localized, distance };
      }
      return localized;
    });
    // Sort by distance when user location is available
    if (userLocation) {
      items.sort((a: any, b: any) => (a.distance || 0) - (b.distance || 0));
    }
    return items;
  }, [listPages, userLocation, localizeRestaurant]);

  // ── Zoom map to selected country ──
  useEffect(() => {
    if (!mapRef.current || !selectedCountry) return;
    const bbox = COUNTRY_BBOX[selectedCountry];
    if (bbox) {
      mapRef.current.fitBounds(
        [[bbox[0], bbox[1]], [bbox[2], bbox[3]]],
        { padding: 30, maxZoom: 8, duration: 800 }
      );
    }
  }, [selectedCountry]);

  const landmarks = listItems;

  // Auto-translate restaurant names for non-base languages
  const [nameTranslations, setNameTranslations] = useState<Record<string, string> | null>(null);
  useAutoTranslateNames(landmarks, setNameTranslations);

  const getDisplayName = (restaurant: any) => {
    if (nameTranslations?.[restaurant.id]) {
      const translated = nameTranslations[restaurant.id].split('\n')[0];
      const orig = restaurant.name || "";
      if (translated.trim().toLowerCase() !== orig.trim().toLowerCase() && orig) {
        return `${translated} · ${orig}`;
      }
      return translated;
    }
    const { displayName, originalName, showDual } = getNameWithOriginal(restaurant);
    if (showDual) {
      return `${displayName} · ${originalName}`;
    }
    return displayName;
  };
  const handleRestaurantClick = (restaurant: any) => {
    navigate(`/restaurant/${restaurant.id}`);
  };

  const handleMarkerClick = async (restaurant: any) => {
    setSelectedRestaurantId(restaurant.id);
    
    const restaurantElement = restaurantRefs.current[restaurant.id];
    if (restaurantElement) {
      // Already loaded in sidebar, just scroll to it
      restaurantElement.scrollIntoView({ 
        behavior: 'smooth', 
        block: 'nearest'
      });
      setSelectedMarkerItem(null);
    } else {
      // Not loaded yet — fetch this single landmark for the sidebar
      try {
        const { data, error } = await supabase
          .from("restaurants")
          .select("id,name,name_en,name_pt,address,lat,lng,rating,type,type_en,type_pt,image_url,cover_image_url,template,translations,country,city")
          .eq("id", restaurant.id)
          .maybeSingle();
        
        if (data && !error) {
          const localized = localizeRestaurant(data as any);
          if (userLocation) {
            const distance = calculateDistance(userLocation.lat, userLocation.lng, data.lat, data.lng);
            setSelectedMarkerItem({ ...localized, distance });
          } else {
            setSelectedMarkerItem(localized);
          }
        }
      } catch (e) {
        console.error("Failed to fetch selected landmark:", e);
      }
    }
  };

  const toggleFullscreen = () => {
    const mapContainer = document.getElementById('home-map-container');
    if (!mapContainer) return;

    if (!isFullscreen) {
      if (mapRef.current) {
        const center = mapRef.current.getCenter();
        const zoom = mapRef.current.getZoom();
        savedMapState.current = { center: [center.lng, center.lat], zoom };
      }
      if (mapContainer.requestFullscreen) {
        mapContainer.requestFullscreen();
      }
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    const handleFullscreenChange = () => {
      const isNowFullscreen = !!document.fullscreenElement;
      setIsFullscreen(isNowFullscreen);
      
      if (!isNowFullscreen && savedMapState.current && mapRef.current) {
        setTimeout(() => {
          mapRef.current?.jumpTo({
            center: savedMapState.current!.center,
            zoom: savedMapState.current!.zoom,
          });
        }, 100);
      }
    };

    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, []);

  return (
    <div className="animate-fade-in">
      {/* Header - Left aligned */}
      <div className="text-left mb-6">
        <h2 className="text-xl sm:text-2xl font-bold text-foreground mb-2 sm:mb-3 flex items-center gap-2">
          <UtensilsCrossed className="w-6 h-6 text-primary" />
          {t("michelinMap.title")}
        </h2>
        <p className="text-sm sm:text-base text-muted-foreground">
          {t("michelinMap.subtitle")}
        </p>
      </div>
        
      {/* Search and Filters */}
      <div className="mb-6 space-y-4">
        {/* Desktop-only: Location & Filter buttons above map. On mobile they appear under "隐藏地图" toggle. */}
        <div className="hidden md:flex flex-col md:flex-row gap-3">
          <Button
            variant={userLocation ? "default" : "outline"}
            onClick={userLocation ? undefined : handleRequestLocation}
            className="md:flex-initial gap-2 h-11 md:px-6"
          >
            <Navigation className={`w-4 h-4 ${userLocation ? 'animate-pulse' : ''}`} />
            {userLocation ? t("restaurants.locationEnabled") : t("restaurants.getLocation")}
          </Button>

          <Button
            variant={showFilters ? "default" : "outline"}
            onClick={() => setShowFilters(!showFilters)}
            className="md:flex-initial gap-2 h-11 md:px-6"
          >
            <Filter className="w-4 h-4" />
            {t("restaurants.filter")}
          </Button>
        </div>

        {/* Filters Container */}
        {showFilters && (
          <div className="space-y-3 bg-card/50 backdrop-blur-sm rounded-lg p-4 border border-border/50 animate-fade-in">
            {/* Country Filters */}
            <div className="space-y-2">
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-sm font-semibold text-foreground">{t("restaurants.country", "国家")}:</span>
                {selectedCountry && (
                  <Badge
                    variant="outline"
                    className="cursor-pointer hover:bg-destructive hover:text-destructive-foreground hover:scale-105 transition-all duration-200 px-2 py-0 text-xs h-5"
                    onClick={() => setSelectedCountry(null)}>
                    {t("common.actions.clearFilter")}
                  </Badge>
                )}
              </div>
              <div className="flex gap-2 flex-wrap">
                {SUPPORTED_COUNTRIES.map((c, index) => (
                  <Badge
                    key={c.db}
                    variant={selectedCountry === c.db ? "default" : "secondary"}
                    className={`cursor-pointer transition-all duration-200 px-3 py-1.5 text-xs whitespace-nowrap hover:scale-105 active:animate-tag-select ${selectedCountry === c.db ? 'ring-2 ring-primary/30 shadow-sm' : ''}`}
                    style={{ animationDelay: `${index * 30}ms` }}
                    onClick={() => setSelectedCountry(selectedCountry === c.db ? null : c.db)}
                  >
                    {c.flag} {t(`countries.${COUNTRY_I18N_MAP[c.db]}`, c.db)}
                  </Badge>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Radius Filter */}
        {userLocation && (
          <div className="flex gap-2 flex-wrap items-center bg-muted/30 backdrop-blur-sm rounded-lg p-3 border border-primary/10">
            <span className="text-sm font-semibold text-primary">{t("restaurants.radius")}:</span>
            <Badge
              variant={radiusFilter === null ? "default" : "secondary"}
              className="cursor-pointer hover:scale-105 transition-transform"
              onClick={() => handleRadiusChange(null)}
            >
              {countryName || t("restaurants.allRestaurants")}
            </Badge>
            <Badge
              variant={radiusFilter === 5 ? "default" : "secondary"}
              className="cursor-pointer hover:scale-105 transition-transform"
              onClick={() => handleRadiusChange(5)}
            >
              {t("restaurants.radius5km")}
            </Badge>
            <Badge
              variant={radiusFilter === 10 ? "default" : "secondary"}
              className="cursor-pointer hover:scale-105 transition-transform"
              onClick={() => handleRadiusChange(10)}
            >
              {t("restaurants.radius10km")}
            </Badge>
            <Badge
              variant={radiusFilter === 20 ? "default" : "secondary"}
              className="cursor-pointer hover:scale-105 transition-transform"
              onClick={() => handleRadiusChange(20)}
            >
              {t("restaurants.radius20km")}
            </Badge>
            <Badge
              variant={radiusFilter === 50 ? "default" : "secondary"}
              className="cursor-pointer hover:scale-105 transition-transform"
              onClick={() => handleRadiusChange(50)}
            >
              50km
            </Badge>
          </div>
        )}
      </div>

      {/* Map and List Layout */}
      {!isLoading && mapMarkers && (
        <div className="flex flex-col lg:flex-row gap-6">
          {/* Map */}
          <div className={`w-full lg:flex-1 transition-all duration-300 ease-in-out ${isMapCollapsed ? 'h-0 overflow-hidden lg:h-[500px]' : 'h-[400px] lg:h-[500px]'}`}>
            <div id="home-map-container" className={`${isFullscreen ? 'fixed inset-0 z-50 bg-background' : 'w-full h-full'} rounded-xl overflow-hidden shadow-2xl border border-primary/10 relative group`}>
              <Button
                variant="secondary"
                size="icon"
                className="absolute bottom-4 right-4 z-10 shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                onClick={toggleFullscreen}
              >
                {isFullscreen ? (
                  <Minimize className="w-5 h-5" />
                ) : (
                  <Maximize className="w-5 h-5" />
                )}
              </Button>
              <div className="h-full relative">
                <RestaurantMap
                  restaurants={mapMarkers as any}
                  onRestaurantClick={handleRestaurantClick}
                  userLocation={userLocation}
                  radiusFilter={radiusFilter}
                  countryBbox={countryBbox}
                  onMarkerClick={handleMarkerClick}
                  showViewDetailsButton={true}
                  disableScrollZoom={true}
                  onMapInit={(mapInstance) => {
                    mapRef.current = mapInstance;
                  }}
                />
                <div className="absolute bottom-4 left-4 z-10 pointer-events-none flex items-center gap-2 bg-background/80 backdrop-blur-sm px-3 py-2 rounded-full shadow-lg">
                  <img 
                    src={logoIcon} 
                    alt="Xiaoxiong Market Logo" 
                    className="h-6 w-6 object-contain"
                  />
                  <span className="text-sm font-semibold text-foreground whitespace-nowrap">
                    {t("home.hero.brandName")}
                  </span>
                </div>
              </div>
            </div>
          </div>
          
          {/* Mobile Map Toggle Button */}
          <Button
            variant="outline"
            size="sm"
            className="lg:hidden flex items-center justify-center gap-2 -mt-3 mb-1"
            onClick={() => setIsMapCollapsed(!isMapCollapsed)}
          >
            {isMapCollapsed ? (
              <>
                <ChevronDown className="w-4 h-4" />
                {t("map.showMap")}
              </>
            ) : (
              <>
                <ChevronUp className="w-4 h-4" />
                {t("map.hideMap")}
              </>
            )}
          </Button>

          {/* Location & Filter buttons - placed under "隐藏地图" toggle (mobile only) */}
          <div className="lg:hidden flex gap-2 -mt-1">
            <Button
              variant={userLocation ? "default" : "outline"}
              onClick={userLocation ? undefined : handleRequestLocation}
              className="flex-1 md:flex-initial gap-2 h-11 md:px-6"
            >
              <Navigation className={`w-4 h-4 ${userLocation ? 'animate-pulse' : ''}`} />
              <span className="md:hidden">{t("restaurants.getLocationMobile")}</span>
              <span className="hidden md:inline">{userLocation ? t("restaurants.locationEnabled") : t("restaurants.getLocation")}</span>
            </Button>

            <Button
              variant={showFilters ? "default" : "outline"}
              onClick={() => setShowFilters(!showFilters)}
              className="flex-1 md:flex-initial gap-2 h-11 md:px-6"
            >
              <Filter className="w-4 h-4" />
              {t("restaurants.filter")}
            </Button>
          </div>

          {/* Landmark List Sidebar */}
          <div className="w-full lg:w-[420px] flex flex-col">
            <div className="mb-4 pb-3 border-b border-border/60">
              <div className="flex items-center justify-between">
                <h2 className="text-lg sm:text-xl font-bold text-foreground flex items-center gap-2">
                  <UtensilsCrossed className="w-5 h-5 text-primary" />
                  {t("michelinMap.listTitle")}
                  <span className="text-xs font-medium text-primary bg-primary/10 px-2 py-0.5 rounded-full">{mapMarkers.length}</span>
                </h2>
                {userLocation && (
                  <span className="text-xs text-muted-foreground flex items-center gap-1">
                    <Navigation className="w-3 h-3" />
                    {t("restaurants.sortedByDistance")}
                  </span>
                )}
              </div>
            </div>
            
            {landmarks.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-12 text-center">
                <UtensilsCrossed className="w-16 h-16 text-muted-foreground/40 mb-4" />
                <h3 className="text-xl font-semibold text-foreground mb-2">
                  {t("michelinMap.empty")}
                </h3>
                <p className="text-muted-foreground max-w-xs">
                  {t("michelinMap.emptyDesc")}
                </p>
              </div>
            ) : (
              <>
                <div className="lg:hidden space-y-2.5 pb-4">
                  {/* Show selected marker item if not in loaded list (mobile) */}
                  {selectedMarkerItem && !landmarks.some(l => l.id === selectedMarkerItem.id) && (
                    <div
                      className="group flex gap-3 p-3 rounded-xl cursor-pointer transition-all duration-200 bg-primary/5 ring-1 ring-primary/30"
                      onClick={() => handleRestaurantClick(selectedMarkerItem)}
                    >
                      <div className="relative w-20 h-20 rounded-lg overflow-hidden flex-shrink-0 bg-muted">
                        {selectedMarkerItem.image_url || selectedMarkerItem.cover_image_url ? (
                          <img 
                            src={selectedMarkerItem.cover_image_url || selectedMarkerItem.image_url} 
                            alt={getLocalizedField(selectedMarkerItem, "name")}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/10 to-primary/5">
                            <MapPin className="w-6 h-6 text-primary/40" />
                          </div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                        <div>
                          <h3 className="font-semibold text-sm text-foreground line-clamp-1">
                            {formatTrademarkSymbols(getDisplayName(selectedMarkerItem))}
                          </h3>
                          {selectedMarkerItem.type?.length > 0 && (
                            <div className="flex gap-1 mt-1 flex-wrap">
                              {selectedMarkerItem.type.slice(0, 2).map((type: string, idx: number) => (
                                <span key={idx} className="text-[11px] text-muted-foreground bg-secondary/80 px-1.5 py-0.5 rounded">
                                  {getTypeDisplayLabel(type, i18n.language)}
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                        <p className="text-xs text-muted-foreground line-clamp-1 mt-1">{selectedMarkerItem.address}</p>
                      </div>
                    </div>
                  )}
                  {(isMobileListExpanded 
                    ? landmarks 
                    : landmarks.slice(0, MOBILE_DEFAULT_VISIBLE)
                  ).map((restaurant, index) => (
                    <div
                      key={restaurant.id}
                      ref={(el) => restaurantRefs.current[restaurant.id] = el}
                      className={`group flex gap-3 p-3 rounded-xl cursor-pointer transition-all duration-200 hover:bg-accent/60 active:scale-[0.98] ${
                        selectedRestaurantId === restaurant.id 
                          ? 'bg-primary/5 ring-1 ring-primary/30' 
                          : 'hover:shadow-sm'
                      }`}
                      onClick={() => handleRestaurantClick(restaurant)}
                    >
                      {/* Thumbnail */}
                      <div className="relative w-20 h-20 rounded-lg overflow-hidden flex-shrink-0 bg-muted">
                        {restaurant.image_url || restaurant.cover_image_url ? (
                          <img 
                            src={restaurant.cover_image_url || restaurant.image_url} 
                            alt={restaurant.name}
                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                            loading="lazy"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/10 to-primary/5">
                            <MapPin className="w-6 h-6 text-primary/40" />
                          </div>
                        )}
                        {restaurant.rating > 0 && (
                          <div className="absolute top-1 right-1 flex items-center gap-0.5 bg-background/90 backdrop-blur-sm px-1.5 py-0.5 rounded-md">
                            <Star className="w-3 h-3" style={{ fill: '#016450', color: '#016450' }} />
                            <span className="text-[10px] font-bold text-primary">{restaurant.rating}</span>
                          </div>
                        )}
                      </div>
                      
                      {/* Info */}
                      <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                        <div>
                          <div className="flex items-center gap-2">
                            <h3 className="font-semibold text-sm text-foreground line-clamp-1 flex-1">
                              {formatTrademarkSymbols(getDisplayName(restaurant))}
                            </h3>
                            {restaurant.distance !== undefined && (
                              <span className="text-xs font-medium text-primary flex-shrink-0">
                                {restaurant.distance < 1 
                                  ? `${(restaurant.distance * 1000).toFixed(0)} m` 
                                  : `${restaurant.distance.toFixed(1)} km`}
                              </span>
                            )}
                          </div>
                          {restaurant.type && restaurant.type.length > 0 && (
                            <div className="flex gap-1 mt-1 flex-wrap">
                              {restaurant.type.slice(0, 2).map((type: string, idx: number) => (
                                <span key={idx} className="text-[11px] text-muted-foreground bg-secondary/80 px-1.5 py-0.5 rounded">
                                  {getTypeDisplayLabel(type, i18n.language)}
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                        <p className="text-xs text-muted-foreground line-clamp-1 mt-1">
                          {restaurant.address}
                        </p>
                      </div>
                    </div>
                  ))}
                  
                  {landmarks.length > MOBILE_DEFAULT_VISIBLE && !isMobileListExpanded && (
                    <Button
                      variant="outline"
                      className="w-full mt-2 gap-2"
                      onClick={() => setIsMobileListExpanded(true)}
                    >
                      <ChevronDown className="w-4 h-4" />
                      {t("landmarks.viewMore", { count: mapMarkers.length })}
                    </Button>
                  )}
                  {isMobileListExpanded && hasNextPage && (
                    <Button
                      variant="outline"
                      className="w-full mt-2 gap-2"
                      onClick={() => fetchNextPage()}
                      disabled={isFetchingNextPage}
                    >
                      {isFetchingNextPage 
                        ? t("common.loading") 
                        : t("common.loadMore")}
                    </Button>
                  )}
                  {isMobileListExpanded && (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="w-full mt-1 gap-2"
                      onClick={() => setIsMobileListExpanded(false)}
                    >
                      <ChevronUp className="w-4 h-4" />
                      {t("map.collapseList")}
                    </Button>
                  )}
                </div>
                
                <ScrollArea className="hidden lg:block h-[420px] pr-2" onScrollCapture={(e) => {
                  const target = e.target as HTMLElement;
                  if (target.scrollHeight - target.scrollTop - target.clientHeight < 200 && hasNextPage && !isFetchingNextPage) {
                    fetchNextPage();
                  }
                }}>
                  <div className="space-y-1 pb-4">
                    {/* Show selected marker item if not in loaded list */}
                    {selectedMarkerItem && !landmarks.some(l => l.id === selectedMarkerItem.id) && (
                      <div
                        ref={(el) => {
                          if (!el) return;
                          // Only auto-scroll once per selection to avoid hijacking the page scroll on re-renders
                          if ((el as any).__scrolledForId === selectedMarkerItem.id) return;
                          (el as any).__scrolledForId = selectedMarkerItem.id;
                          el.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
                        }}
                        className="group flex gap-3 p-3 rounded-xl cursor-pointer transition-all duration-200 bg-primary/5 ring-1 ring-primary/30 mb-2"
                        onClick={() => handleRestaurantClick(selectedMarkerItem)}
                      >
                        <div className="relative w-[72px] h-[72px] rounded-lg overflow-hidden flex-shrink-0 bg-muted">
                          {selectedMarkerItem.image_url || selectedMarkerItem.cover_image_url ? (
                            <img 
                              src={selectedMarkerItem.cover_image_url || selectedMarkerItem.image_url} 
                              alt={getLocalizedField(selectedMarkerItem, "name")}
                              className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                            />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/10 to-primary/5">
                              <MapPin className="w-5 h-5 text-primary/40" />
                            </div>
                          )}
                          {selectedMarkerItem.rating > 0 && (
                            <div className="absolute top-1 right-1 flex items-center gap-0.5 bg-background/90 backdrop-blur-sm px-1.5 py-0.5 rounded-md">
                              <Star className="w-3 h-3" style={{ fill: '#016450', color: '#016450' }} />
                              <span className="text-[10px] font-bold text-primary">{selectedMarkerItem.rating}</span>
                            </div>
                          )}
                        </div>
                        <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                          <div>
                            <div className="flex items-center gap-2">
                              <h3 className="font-semibold text-sm text-foreground line-clamp-1 flex-1">
                                {formatTrademarkSymbols(getDisplayName(selectedMarkerItem))}
                              </h3>
                              {selectedMarkerItem.distance !== undefined && (
                                <span className="text-xs font-medium text-primary flex-shrink-0">
                                  {selectedMarkerItem.distance < 1 
                                    ? `${(selectedMarkerItem.distance * 1000).toFixed(0)} m` 
                                    : `${selectedMarkerItem.distance.toFixed(1)} km`}
                                </span>
                              )}
                            </div>
                            {selectedMarkerItem.type && selectedMarkerItem.type.length > 0 && (
                              <div className="flex gap-1 mt-1 flex-wrap">
                                {selectedMarkerItem.type.slice(0, 2).map((type: string, idx: number) => (
                                  <span key={idx} className="text-[11px] text-muted-foreground bg-secondary/80 px-1.5 py-0.5 rounded">
                                    {getTypeDisplayLabel(type, i18n.language)}
                                  </span>
                                ))}
                              </div>
                            )}
                          </div>
                          <p className="text-xs text-muted-foreground line-clamp-1 mt-1">
                            {selectedMarkerItem.address}
                          </p>
                        </div>
                      </div>
                    )}
                    {landmarks.map((restaurant, index) => (
                      <div
                        key={restaurant.id}
                        ref={(el) => restaurantRefs.current[restaurant.id] = el}
                        className={`group flex gap-3 p-3 rounded-xl cursor-pointer transition-all duration-200 hover:bg-accent/60 ${
                          selectedRestaurantId === restaurant.id 
                            ? 'bg-primary/5 ring-1 ring-primary/30' 
                            : 'hover:shadow-sm'
                        }`}
                        onClick={() => handleRestaurantClick(restaurant)}
                      >
                        {/* Thumbnail */}
                        <div className="relative w-[72px] h-[72px] rounded-lg overflow-hidden flex-shrink-0 bg-muted">
                          {restaurant.image_url || restaurant.cover_image_url ? (
                            <img 
                              src={restaurant.cover_image_url || restaurant.image_url} 
                              alt={getLocalizedField(restaurant, "name")}
                              className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                              loading="lazy"
                            />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/10 to-primary/5">
                              <MapPin className="w-5 h-5 text-primary/40" />
                            </div>
                          )}
                          {restaurant.rating > 0 && (
                            <div className="absolute top-1 right-1 flex items-center gap-0.5 bg-background/90 backdrop-blur-sm px-1.5 py-0.5 rounded-md">
                              <Star className="w-3 h-3" style={{ fill: '#016450', color: '#016450' }} />
                              <span className="text-[10px] font-bold text-primary">{restaurant.rating}</span>
                            </div>
                          )}
                        </div>
                        
                        {/* Info */}
                        <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                          <div>
                            <div className="flex items-center gap-2">
                              <h3 className="font-semibold text-sm text-foreground line-clamp-1 flex-1">
                                {formatTrademarkSymbols(getDisplayName(restaurant))}
                              </h3>
                              {restaurant.distance !== undefined && (
                                <span className="text-xs font-medium text-primary flex-shrink-0">
                                  {restaurant.distance < 1 
                                    ? `${(restaurant.distance * 1000).toFixed(0)} m` 
                                    : `${restaurant.distance.toFixed(1)} km`}
                                </span>
                              )}
                            </div>
                            {restaurant.type && restaurant.type.length > 0 && (
                              <div className="flex gap-1 mt-1 flex-wrap">
                                {restaurant.type.slice(0, 2).map((type: string, idx: number) => (
                                  <span key={idx} className="text-[11px] text-muted-foreground bg-secondary/80 px-1.5 py-0.5 rounded">
                                    {getTypeDisplayLabel(type, i18n.language)}
                                  </span>
                                ))}
                              </div>
                            )}
                          </div>
                          <p className="text-xs text-muted-foreground line-clamp-1 mt-1">
                            {restaurant.address}
                          </p>
                        </div>
                      </div>
                    ))}
                    {isFetchingNextPage && (
                      <div className="flex justify-center py-4">
                        <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-primary"></div>
                      </div>
                    )}
                  </div>
                </ScrollArea>
              </>
            )}
          </div>
        </div>
      )}

      <LocationPermissionDialog
        open={showLocationDialog}
        onOpenChange={setShowLocationDialog}
        onConfirm={requestLocation}
      />
    </div>
  );
};

export default HomeMapSection;
